if (! function_exists('data_train_test_split')) {
    function data_train_test_split($values, $train_ratio = null, $shuffle = null, $seed = null, $stratify = null)
    {
        if (!is_array($values) || count($values) < 2) {
            return json_encode(['error' => 'Need at least 2 values to split', 'train' => [], 'test' => []]);
        }
        $n = count($values);
        $ratio = isset($train_ratio) ? min(0.99, max(0.01, (float)$train_ratio)) : 0.8;
        $doShuffle = isset($shuffle) ? (bool)$shuffle : true;
        $seed = isset($seed) ? (int)$seed : 0;
        $stratifyLabels = isset($stratify) && is_array($stratify) ? $stratify : null;

        // Create indices
        $indices = range(0, $n - 1);

        if ($stratifyLabels !== null) {
            if (count($stratifyLabels) !== $n) {
                return json_encode(['error' => 'stratify array must have same length as values']);
            }
            // Stratified split: group indices by class, split each group
            $groups = [];
            foreach ($stratifyLabels as $i => $label) {
                $key = is_bool($label) ? ($label ? 'true' : 'false') : (string)$label;
                if (!isset($groups[$key])) $groups[$key] = [];
                $groups[$key][] = $i;
            }
            
            if ($doShuffle) {
                if ($seed > 0) srand($seed);
                foreach ($groups as &$g) {
                    shuffle($g);
                }
            }
            
            $trainIdx = [];
            $testIdx = [];
            foreach ($groups as $g) {
                $groupCount = count($g);
                $nTrain = max(1, (int)round($groupCount * $ratio));
                // Ensure at least 1 in test if possible
                if ($groupCount - $nTrain < 1 && $groupCount > 1) {
                    $nTrain = $groupCount - 1;
                }
                for ($i = 0; $i < $nTrain; $i++) $trainIdx[] = $g[$i];
                for ($i = $nTrain; $i < $groupCount; $i++) $testIdx[] = $g[$i];
            }
            
            $indices = array_merge($trainIdx, $testIdx);
            $splitPoint = count($trainIdx);
        } else {
            // Simple random or sequential split
            if ($doShuffle) {
                if ($seed > 0) srand($seed);
                shuffle($indices);
            }
            $splitPoint = max(1, (int)round($n * $ratio));
            // Ensure at least 1 in test
            if ($splitPoint >= $n) $splitPoint = $n - 1;
        }

        $train = [];
        $test = [];
        for ($i = 0; $i < $splitPoint; $i++) {
            $train[] = [
                'index' => $indices[$i],
                'value' => $values[$indices[$i]],
                'stratify_label' => $stratifyLabels !== null ? $stratifyLabels[$indices[$i]] : null,
