            $testLabels = array_map(function($t) { return $t['stratify_label']; }, $test);
            $trainDist = array_count_values(array_map('strval', $trainLabels));
            $testDist = array_count_values(array_map('strval', $testLabels));
            $classDist = [
                'train' => $trainDist,
                'test' => $testDist,
            ];
        }

        return json_encode([
